file.content:
{
	"$schema": "https://schemas.wp.org/trunk/block.json",
	"apiVersion": 3,
	"name": "telex/block-telex-date-expiry-block",
	"version": "0.1.0",
	"title": "Date Expiry Text Block",
	"category": "text",
	"icon": "calendar-alt",
	"description": "Displays custom text when a specified custom field date has passed.",
	"example": {
		"attributes": {
			"customFieldName": "expiry_date",
			"dateFormat": "Y-m-d",
			"content": "This content has expired."
		}
	},
	"attributes": {
		"customFieldName": {
			"type": "string",
			"default": ""
		},
		"dateFormat": {
			"type": "string",
			"default": "Y-m-d"
		},
		"content": {
			"type": "string",
			"default": ""
		},
		"textAlign": {
			"type": "string"
		}
	},
	"supports": {
		"html": false,
		"color": {
			"gradients": true,
			"text": true,
			"background": true
		},
		"typography": {
			"fontSize": true,
			"lineHeight": true,
			"__experimentalFontFamily": true,
			"__experimentalFontWeight": true,
			"__experimentalFontStyle": true,
			"__experimentalTextTransform": true,
			"__experimentalTextDecoration": true,
			"__experimentalLetterSpacing": true
		},
		"spacing": {
			"margin": true,
			"padding": true
		},
		"__experimentalBorder": {
			"radius": true,
			"width": true,
			"color": true,
			"style": true
		}
	},
	"textdomain": "telex-date-expiry-block",
	"editorScript": "file:./index.js",
	"editorStyle": "file:./index.css",
	"style": "file:./style-index.css",
	"viewScript": "file:./view.js",
	"render": "file:./render.php"
}

/**
 * Registers a new block provided a unique name and an object defining its behavior.
 *
 * @see https://developer.wordpress.org/block-editor/reference-guides/block-api/block-registration/
 */
import { registerBlockType } from '@wordpress/blocks';

/**
 * Lets webpack process CSS, SASS or SCSS files referenced in JavaScript files.
 * All files containing `style` keyword are bundled together. The code used
 * gets applied both to the front of your site and to the editor.
 *
 * @see https://www.npmjs.com/package/@wordpress/scripts#using-css
 */
import './style.scss';

/**
 * Internal dependencies
 */
import Edit from './edit';
import metadata from './block.json';

/**
 * Every block starts by registering a new block type definition.
 *
 * @see https://developer.wordpress.org/block-editor/reference-guides/block-api/block-registration/
 */
registerBlockType( metadata.name, {
	/**
	 * @see ./edit.js
	 */
	edit: Edit,
} );

/**
 * Retrieves the translation of text.
 *
 * @see https://developer.wordpress.org/block-editor/reference-guides/packages/packages-i18n/
 */
import { __ } from '@wordpress/i18n';

/**
 * React hook that is used to mark the block wrapper element.
 * It provides all the necessary props like the class name.
 *
 * @see https://developer.wordpress.org/block-editor/reference-guides/packages/packages-block-editor/#useblockprops
 */
import {
	useBlockProps,
	RichText,
	BlockControls,
	AlignmentToolbar,
	InspectorControls,
} from '@wordpress/block-editor';

import {
	PanelBody,
	TextControl,
	Notice,
} from '@wordpress/components';

/**
 * Lets webpack process CSS, SASS or SCSS files referenced in JavaScript files.
 * Those files can contain any CSS code that gets applied to the editor.
 *
 * @see https://www.npmjs.com/package/@wordpress/scripts#using-css
 */
import './editor.scss';

/**
 * The edit function describes the structure of your block in the context of the
 * editor. This represents what the editor will render when the block is used.
 *
 * @see https://developer.wordpress.org/block-editor/reference-guides/block-api/block-edit-save/#edit
 *
 * @return {Element} Element to render.
 */
export default function Edit( { attributes, setAttributes } ) {
	const { customFieldName, dateFormat, content, textAlign } = attributes;

	const blockProps = useBlockProps( {
		style: {
			textAlign: textAlign || undefined,
		},
	} );

	return (
		<>
			<BlockControls>
				<AlignmentToolbar
					value={ textAlign }
					onChange={ ( newAlign ) =>
						setAttributes( { textAlign: newAlign } )
					}
				/>
			</BlockControls>
			<InspectorControls>
				<PanelBody
					title={ __(
						'Expiry Settings',
						'telex-date-expiry-block'
					) }
				>
					<TextControl
						label={ __(
							'Custom Field Name',
							'telex-date-expiry-block'
						) }
						help={ __(
							'Enter the meta key name that stores the expiry date.',
							'telex-date-expiry-block'
						) }
						value={ customFieldName }
						onChange={ ( value ) =>
							setAttributes( { customFieldName: value } )
						}
					/>
					<TextControl
						label={ __(
							'Date Format',
							'telex-date-expiry-block'
						) }
						help={ __(
							'PHP date format of the custom field value. Default: Y-m-d',
							'telex-date-expiry-block'
						) }
						value={ dateFormat }
						onChange={ ( value ) =>
							setAttributes( { dateFormat: value } )
						}
					/>
				</PanelBody>
			</InspectorControls>
			<div { ...blockProps }>
				{ ! customFieldName && (
					<div className="telex-date-expiry-block-notice">
						<Notice status="warning" isDismissible={ false }>
							{ __(
								'Please set a custom field name in the block settings.',
								'telex-date-expiry-block'
							) }
						</Notice>
					</div>
				) }
				<RichText
					tagName="p"
					value={ content }
					onChange={ ( value ) =>
						setAttributes( { content: value } )
					}
					placeholder={ __(
						'Enter text to display when the date has expired…',
						'telex-date-expiry-block'
					) }
					allowedFormats={ [
						'core/bold',
						'core/italic',
						'core/link',
						'core/strikethrough',
						'core/underline',
						'core/text-color',
						'core/subscript',
						'core/superscript',
						'core/code',
					] }
				/>
			</div>
		</>
	);
}

/**
 * The following styles get applied both on the front of your site
 * and in the editor.
 */

.wp-block-telex-block-telex-date-expiry-block {
	p {
		margin: 0;
	}
}

/**
 * The following styles get applied inside the editor only.
 */

.wp-block-telex-block-telex-date-expiry-block {
	.telex-date-expiry-block-notice {
		margin-bottom: 8px;

		.components-notice {
			margin: 0;
		}
	}
}

{
	"name": "telex-date-expiry-block",
	"version": "0.1.0",
	"description": "A block that displays custom text when a specified custom field date has passed.",
	"author": "WordPress Telex",
	"license": "GPL-2.0-or-later",
	"main": "build/index.js",
	"scripts": {
		"build": "wp-scripts build",
		"format": "wp-scripts format",
		"lint:css": "wp-scripts lint-style",
		"lint:js": "wp-scripts lint-js",
		"packages-update": "wp-scripts packages-update",
		"plugin-zip": "wp-scripts plugin-zip",
		"start": "wp-scripts start"
	},
	"devDependencies": {
		"@wordpress/scripts": "^30.15.0"
	}
}
